def encode(message):
    """
    Write a function that takes a message, and encodes in such a 
    way that it swaps case of all letters, replaces all vowels in 
    the message with the letter that appears 2 places ahead of that 
    vowel in the english alphabet. 
    Assume only letters. 

    Examples:
    >>> encode('test')
    'TGST'
    >>> encode('This is a message')
    'tHKS KS C MGSSCGG'
    """

    result = []
    for char in message:
        if char.isalpha():
            # Swap case
            if char.islower():
                new_char = char.upper()
            else:
                new_char = char.lower()

            # Replace vowels
            if new_char in 'AEIOUaeiou':
                if new_char in 'AEIOU':
                    new_char = chr(ord(new_char) + 2)  # uppercase vowels
                else:
                    new_char = chr(ord(new_char) + 2)  # lowercase vowels

            result.append(new_char)
        else:
            result.append(char)

    return ''.join(result)
